class OrderIdGenerator {
    private final java.util.concurrent.atomic.AtomicLong seq = new java.util.concurrent.atomic.AtomicLong(0);

    String nextId() {
        long n = seq.incrementAndGet();
        return String.format("ORD-%06d", n);
    }
}
